  ('police-94737317-moex-00247', 'police-94737317', 'police-94737317-moex-110-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋，有關總統之刑事豁免權，下列敘述何者正確？', '["總統有刑事豁免權，故檢察官不得發動任何偵查權", "如不妨害總統職權之正常行使，得對總統以被告身分進行偵查", "得為保全必要證據而限制總統之人身自由", "總統如涉嫌內亂罪，檢察官仍得偵查起訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:57+00:00", "source_pdf_sha1": "2bb3abaf887b", "answer_pdf_sha1": "de44332422d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
