  ('police-94737317-moex-00249', 'police-94737317', 'police-94737317-moex-110-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依憲法及司法院大法官解釋，關於立法委員之言論免責權，下列敘述何者正確？', '["言論免責權的目的係使立法委員行使職權無所顧慮，以便於監督政府，故應作最大程度之界定", "「對院外不負責任」包含不負相關民事責任、刑事責任及違反自律規則之行政責任", "立法委員參加電視台政論節目所發表的言論，亦享有言論免責權", "立法委員在休會期間不受言論免責權的保障"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:57+00:00", "source_pdf_sha1": "2bb3abaf887b", "answer_pdf_sha1": "de44332422d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00250', 'police-94737317', 'police-94737317-moex-110-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋，有關宣告法律違憲並定期失效的大法官解釋之效力，下列敘述何者錯誤？', '["定期失效宣告係為避免立即失效所可能造成之法律真空狀態", "定期失效宣告兼有尊重立法機關行使權力及促使其審慎立法之考量", "大法官宣告法律違憲並定期失效，聲請人得立即據該解釋請求再審或其他救濟", "大法官如宣告定期失效，聲請人於法律失效前，無從提起再審或其他救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:57+00:00", "source_pdf_sha1": "2bb3abaf887b", "answer_pdf_sha1": "de44332422d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
