  ('police-94737317-moex-00254', 'police-94737317', 'police-94737317-moex-110-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋，關於憲法第14條結社自由之保障，下列敘述何者錯誤？', '["保障人民為特定目的，以共同之意思，自由選定結社目的組成團體", "確保人民所組成之團體得自主決定其內部組織與事務", "確保人民所組成之各種不同團體，受法律保障與限制之程度相同", "確保人民所組成之團體對外活動不受不法之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:57+00:00", "source_pdf_sha1": "2bb3abaf887b", "answer_pdf_sha1": "de44332422d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00255', 'police-94737317', 'police-94737317-moex-110-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '依司法院大法官解釋，關於婚姻制度，下列敘述何者錯誤？', '["一夫一妻婚姻制度係為維護配偶間之人格倫理關係，實現男女平等原則，及維持社會秩序，受憲法保障", "對於配偶不得提起自訴，係為維護人倫關係之合理限制", "同性婚姻不得適用民法婚姻章規定，只能以專法規範", "結婚自由包括選擇與異性別或同性別之人結婚之自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:57+00:00", "source_pdf_sha1": "2bb3abaf887b", "answer_pdf_sha1": "de44332422d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "602", "s": "0209", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL)
